import{c as a}from"./app.8935f5f1.js";const n={},s=a('<h2 id="禁止from-disk-cache-禁止浏览器缓存问题" tabindex="-1"><a class="header-anchor" href="#禁止from-disk-cache-禁止浏览器缓存问题" aria-hidden="true">#</a> 禁止from disk cache，禁止浏览器缓存问题</h2><ul><li>在url后增加时间戳，这样每次访问的url都不一样了。也就没有缓存了。</li><li>同理。页面跳转刷新有缓存时，也可以在url后增加时间戳参数，就可以解决。</li></ul><div class="language-javascript ext-js"><pre class="language-javascript"><code>\t<span class="token keyword">let</span> rnd <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">getTime</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\t<span class="token keyword">let</span> url <span class="token operator">=</span> url<span class="token operator">+</span><span class="token string">&#39;?t=&#39;</span><span class="token operator">+</span>Math<span class="token punctuation">.</span><span class="token function">random</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre></div>',3);n.render=function(a,n){return s};export{n as default};
